// src/components/FormAluno.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { user } = useAuth();
  const token = user.token;

  // Campos de texto existentes
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [box, setBox] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Novos campos:
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno'); // valor padrão = "aluno"

  // Lista de períodos
  const [periodos, setPeriodos] = useState([]);

  // Boxes do aluno

  const [novoConteudo, setNovoConteudo] = useState('');

  const alunoId = alunoEditando?.id;

  // Carrega períodos
  useEffect(() => {
    const headers = { Authorization: `Bearer ${token}` };
    axios
      .get('/api/periodos', { headers })
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, [token]);

  // Carrega boxes do aluno
  useEffect(() => {
    const headers = { Authorization: `Bearer ${token}` };
    if (alunoId) {
      axios
        .get(`/api/boxes/${alunoId}`, { headers })
        .then(res => setBoxes(res.data))
        .catch(err => console.error('Erro ao carregar boxes:', err));
    } else {
      setBoxes([]);
    }
  }, [alunoId, token]);

  // Preenche dados em edição
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(
        alunoEditando.periodo_id != null ? String(alunoEditando.periodo_id) : ''
      );
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha('');
    } else {
      setNome('');
      setRa('');
      setPeriodoId('');
      setUsuario('');
      setSenha('');
      setRole('aluno');
      setMensagem('');
      setBoxes([]);
    }
  }, [alunoEditando]);

  function validarNomeCompleto(nome) {
    const partes = nome.trim().split(' ').filter(p => p.length >= 2);
    return partes.length >= 2;
  }
  function validarRA(ra) {
    return /^\d{1,9}$/.test(ra);
  }

  const handleCriarBox = () => {
    if (!novoConteudo || !alunoId) return;
    const headers = { Authorization: `Bearer ${token}` };
    axios
      .post(
        '/api/boxes',
        { aluno_id: alunoId, conteudo: novoConteudo },
        { headers }
      )
      .then(res => {
        setBoxes(prev => [res.data, ...prev]);
        setNovoConteudo('');
      })
      .catch(err => console.error(err));
  };

  const handleDeletarBox = id => {
    const headers = { Authorization: `Bearer ${token}` };
    axios
      .delete(`/api/boxes/${id}`, { headers })
      .then(() => setBoxes(prev => prev.filter(b => b.id !== id)))
      .catch(err => console.error(err));
  };

  const handleSubmit = e => {
    e.preventDefault();

    if (!validarNomeCompleto(nome)) {
      setMensagem('Informe o nome completo!');
      return;
    }
    if (!validarRA(ra)) {
      setMensagem('O RA deve conter apenas números e até 9 dígitos!');
      return;
    }
    if (!usuario.trim()) {
      setMensagem('Insira um usuário para login!');
      return;
    }
    if (!alunoEditando && senha.length < 4) {
      setMensagem('Senha deve ter no mínimo 4 caracteres!');
      return;
    }
    if (!periodoId) {
      setMensagem('Selecione um período!');
      return;
    }

    const headers = { Authorization: `Bearer ${token}` };
    const dados = { nome, ra, periodo_id: periodoId, usuario, senha, role };

    if (alunoEditando) {
      const payload = { nome, ra, periodo_id: periodoId, usuario, role };
      if (senha) payload.senha = senha;
      axios
        .put(`/api/alunos/${alunoId}`, payload, { headers })
        .then(() => {
          setMensagem('Aluno atualizado com sucesso!');
          onNovoAluno();
          onFimEdicao();
        })
        .catch(err =>
          setMensagem(err.response?.data?.error || 'Erro ao atualizar aluno.')
        );
    } else {
      axios
        .post('/api/alunos', dados, { headers })
        .then(() => {
          setMensagem('Aluno cadastrado com sucesso!');
          onNovoAluno();
          setTimeout(() => {
            onFimEdicao();
            setMensagem('');
          }, 1500);
        })
        .catch(err =>
          setMensagem(err.response?.data?.error || 'Erro ao cadastrar aluno.')
        );
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-xl font-bold">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      {/* Nome Completo */}
      <div>
        <label className="block font-medium mb-1">Nome Completo:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          value={nome}
          onChange={e => setNome(e.target.value)}
          required
        />
      </div>

      {/* RA e Box lado a lado */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block font-medium mb-1">RA:</label>
          <input
            type="text"
            className="w-full border rounded px-3 py-2"
            value={ra}
            onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0, 9))}
            maxLength={9}
            required
          />
        </div>
         {/* RA e Box lado a lado */}

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block font-medium mb-1">RA:</label>
          <input
            type="text"
            className="w-full border rounded px-3 py-2"
            value={ra}
            onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0, 9))}
            maxLength={9}
            required
          />
        </div>
        <div>
          <label className="block font-medium mb-1">Box:</label>
          <input
            type="text"
            className="w-full border rounded px-3 py-2"
            value={box}
            onChange={e => setBox(e.target.value.replace(/\D/g, '').slice(0, 3))}
            maxLength={3}
          />
        </div>
      </div>

      </div>

      {/* Período */}
      <div>
        <label className="block font-medium mb-1">Período:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={periodoId}
          onChange={e => setPeriodoId(e.target.value)}
          required
        >
          <option value="">Selecione um período</option>
          {periodos.map(p => (
            <option key={p.id} value={String(p.id)}>
              {p.nome} ({p.turno})
            </option>
          ))}
        </select>
      </div>

      {/* Usuário, Senha, Role (sem mudança) */}
      <div>
        <label className="block font-medium mb-1">Login:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          placeholder="Exemplo: Número do seu RA"
          value={usuario}
          onChange={e => setUsuario(e.target.value)}
          required
        />
      </div>
      <div>
        <label className="block font-medium mb-1">
          {alunoEditando ? 'Nova senha (opcional)' : 'Senha:'}
        </label>
        <input
          type="password"
          className="w-full border rounded px-3 py-2"
          value={senha}
          onChange={e => setSenha(e.target.value)}
          required={!alunoEditando}
        />
      </div>
      <div>
        <label className="block font-medium mb-1">Permissão:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={role}
          onChange={e => setRole(e.target.value)}
        >
          <option value="aluno">Aluno</option>
          <option value="recepcao">Recepção</option>
        </select>
      </div>



      {/* Botões */}
      <div className="flex items-center gap-4 mt-4">
        <button
          type="submit"
          className="bg-[#1A1C2C] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#3B4854]"
        >
          {alunoEditando ? 'Atualizar' : 'Cadastrar'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            className="bg-[#DA3648] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#BC3140]"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && (
        <p
          className={`mt-2 ${
            mensagem.toLowerCase().includes('sucesso')
              ? 'text-green-600'
              : 'text-red-600'
          }`}
        >
          {mensagem}
        </p>
      )}
    </form>
  );
}

export default FormAluno;
